import React, { useState, useEffect } from 'react';
import { fetchLeaderboard } from '../utils/typingApi';
import '../styles/Leaderboard.css';

export default function Leaderboard() {
  const [leaderboard, setLeaderboard] = useState([]);
  const [loading, setLoading] = useState(true);
  const [sortBy, setSortBy] = useState('wpm');

  useEffect(() => {
    const loadLeaderboard = async () => {
      setLoading(true);
      const data = await fetchLeaderboard(100);
      setLeaderboard(data);
      setLoading(false);
    };
    loadLeaderboard();
  }, []);

  const sortedLeaderboard = [...leaderboard].sort((a, b) => {
    if (sortBy === 'wpm') return b.wpm - a.wpm;
    if (sortBy === 'accuracy') return b.accuracy - a.accuracy;
    if (sortBy === 'wins') return b.wins - a.wins;
    return 0;
  });

  const getMedalEmoji = (rank) => {
    if (rank === 1) return '🥇';
    if (rank === 2) return '🥈';
    if (rank === 3) return '🥉';
    return '  ';
  };

  return (
    <div className="leaderboard-container">
      <div className="leaderboard-header">
        <h1>🏅 Global Leaderboard</h1>
        <p>The fastest typists in the world</p>
      </div>

      <div className="sort-buttons">
        <button
          className={`sort-btn ${sortBy === 'wpm' ? 'active' : ''}`}
          onClick={() => setSortBy('wpm')}
        >
          Fastest (WPM)
        </button>
        <button
          className={`sort-btn ${sortBy === 'accuracy' ? 'active' : ''}`}
          onClick={() => setSortBy('accuracy')}
        >
          Most Accurate
        </button>
        <button
          className={`sort-btn ${sortBy === 'wins' ? 'active' : ''}`}
          onClick={() => setSortBy('wins')}
        >
          Most Wins
        </button>
      </div>

      {loading ? (
        <div className="loading">Loading leaderboard...</div>
      ) : (
        <div className="leaderboard-table">
          <div className="table-header">
            <div className="col-rank">Rank</div>
            <div className="col-player">Player</div>
            <div className="col-wpm">WPM</div>
            <div className="col-accuracy">Accuracy</div>
            <div className="col-races">Races</div>
            <div className="col-wins">Wins</div>
            <div className="col-earnings">Balance</div>
          </div>

          {sortedLeaderboard.map((player, idx) => (
            <div key={player.id} className={`table-row ${idx < 3 ? 'top-3' : ''}`}>
              <div className="col-rank">
                {getMedalEmoji(idx + 1)}
                <span className="rank-number">#{idx + 1}</span>
              </div>
              <div className="col-player">
                <span className="player-name">{player.username}</span>
              </div>
              <div className="col-wpm">
                <span className="stat-badge">{player.wpm} WPM</span>
              </div>
              <div className="col-accuracy">
                <span className="stat-badge">{player.accuracy.toFixed(1)}%</span>
              </div>
              <div className="col-races">
                <span>{player.totalRaces}</span>
              </div>
              <div className="col-wins">
                <span className="wins-badge">{player.wins}</span>
              </div>
              <div className="col-earnings">
                <span className="earnings">KES {player.balance.toLocaleString()}</span>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
